};

export type IndependencePhase = {
  id: IndependencePhaseId;
  /** 1..4 — matches the owner's phase order. */
  order: number;
  title: string;
  objective: string;
  /** Rork's role in this phase. */
  rorkRole: string;
  requirements: PhaseRequirement[];
